export function processOrders(orders) {
  const result = [];
  for (let i = 0; i < orders.length; i++) {
    const order = orders[i];
    if (order.status !== 'active') {
      continue;
    }
    let found = false;
    for (let j = 0; j < result.length; j++) {
      if (result[j].customer === order.customer) {
        result[j].total = result[j].total + order.amount;
        result[j].orderCount = result[j].orderCount + 1;
        found = true;
        break;
      }
    }
    if (!found) {
      result.push({
        customer: order.customer,
        total: order.amount,
        orderCount: 1
      });
    }
  }
  for (let i = 0; i < result.length - 1; i++) {
    for (let j = 0; j < result.length - i - 1; j++) {
      if (result[j].total < result[j + 1].total) {
        const temp = result[j];
        result[j] = result[j + 1];
        result[j + 1] = temp;
      }
    }
  }
  return result;
}

