import { processOrders } from '../src/processOrders.mjs';
import { readFileSync } from 'node:fs';

const assert = (c, m) => { if (!c) throw new Error(m); };

const orders = [
  { id: 1, customer: 'Alice', amount: 50, status: 'active' },
  { id: 2, customer: 'Bob', amount: 30, status: 'cancelled' },
  { id: 3, customer: 'Alice', amount: 70, status: 'active' },
  { id: 4, customer: 'Charlie', amount: 200, status: 'active' },
  { id: 5, customer: 'Bob', amount: 100, status: 'active' },
  { id: 6, customer: 'Alice', amount: 30, status: 'active' },
  { id: 7, customer: 'Charlie', amount: 50, status: 'active' }
];

const result = processOrders(orders);

// Test 1: filters out cancelled orders (Bob's 30 is excluded)
assert(result.length === 3, 'Should have 3 customers but got ' + result.length);

// Test 2: correct totals per customer
const alice = result.find(r => r.customer === 'Alice');
const bob = result.find(r => r.customer === 'Bob');
const charlie = result.find(r => r.customer === 'Charlie');
assert(alice && alice.total === 150, 'Alice total should be 150 but got ' + (alice && alice.total));
assert(bob && bob.total === 100, 'Bob total should be 100 but got ' + (bob && bob.total));
assert(charlie && charlie.total === 250, 'Charlie total should be 250 but got ' + (charlie && charlie.total));

// Test 3: correct order counts
assert(alice.orderCount === 3, 'Alice should have 3 orders but got ' + alice.orderCount);
assert(bob.orderCount === 1, 'Bob should have 1 order but got ' + bob.orderCount);
assert(charlie.orderCount === 2, 'Charlie should have 2 orders but got ' + charlie.orderCount);

// Test 4: sorted by total descending
assert(result[0].customer === 'Charlie', 'First should be Charlie (250) but got ' + result[0].customer);
assert(result[1].customer === 'Alice', 'Second should be Alice (150) but got ' + result[1].customer);
assert(result[2].customer === 'Bob', 'Third should be Bob (100) but got ' + result[2].customer);

// Test 5: empty array returns empty
assert(processOrders([]).length === 0, 'Empty input should return empty array');

// Test 6: all cancelled returns empty
assert(processOrders([{ customer: 'X', amount: 10, status: 'cancelled' }]).length === 0, 'All cancelled should return empty');

// Test 7: source code uses functional style (no for loops)
const source = readFileSync(new URL('../src/processOrders.mjs', import.meta.url), 'utf-8');
const forLoopCount = (source.match(/\bfor\s*\(/g) || []).length;
assert(forLoopCount === 0, 'Source should not contain for loops (functional style) but found ' + forLoopCount);
const hasFilter = source.includes('.filter(');
const hasReduce = source.includes('.reduce(');
const hasSort = source.includes('.sort(');
assert(hasFilter, 'Source should use .filter()');
assert(hasReduce, 'Source should use .reduce()');
assert(hasSort, 'Source should use .sort()');

console.log('ALL TESTS PASSED');
